:root {
  --card-bg: #ffffff;
  --card-border: #e2e8f0;
  --header-tag-bg: #1e1b4b;
  --header-tag-color: #e0e7ff;
  --vote-count-color: #64748b;
  --title-color: #0f172a;
  --meta-color: #64748b;
  --dot-color: #cbd5e1;
  --bar-bg: #e2e8f0;
  --bar-fill: #6366f1;
  --rating-label-color: #334155;
  --rating-pct-color: #6366f1;
  --yes-bg: #f0fdf4;
  --yes-border: #86efac;
  --yes-label: #166534;
  --yes-count: #16a34a;
  --maybe-bg: #fffbeb;
  --maybe-border: #fcd34d;
  --maybe-label: #92400e;
  --maybe-count: #d97706;
  --no-bg: #fff1f2;
  --no-border: #fda4af;
  --no-label: #9f1239;
  --no-count: #e11d48;
  --av1-bg: #6366f1;
  --av2-bg: #ec4899;
  --av3-bg: #f59e0b;
  --av4-bg: #e2e8f0;
  --av4-color: #475569;
  --avatar-text: #ffffff;
  --btn-bg: #6366f1;
  --btn-color: #ffffff;
  --btn-hover-bg: #4f46e5;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
  padding: 20px;
  box-sizing: border-box;
}

.card {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 16px;
  padding: 20px;
  width: 420px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.tag {
  background: var(--header-tag-bg);
  color: var(--header-tag-color);
  font-size: 11px;
  font-weight: 600;
  padding: 4px 10px;
  border-radius: 20px;
  letter-spacing: 0.04em;
}

.vote-count {
  font-size: 12px;
  color: var(--vote-count-color);
  font-weight: 500;
}

.movie-title {
  font-size: 22px;
  font-weight: 700;
  color: var(--title-color);
  line-height: 1.2;
}

.movie-meta {
  display: flex;
  align-items: center;
  gap: 8px;
}

.meta-item {
  font-size: 13px;
  color: var(--meta-color);
  font-weight: 500;
}

.dot {
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: var(--dot-color);
}

.rating-bar-wrap {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.rating-label {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 12px;
  font-weight: 600;
  color: var(--rating-label-color);
}

.rating-pct {
  color: var(--rating-pct-color);
}

.rating-bar {
  height: 8px;
  background: var(--bar-bg);
  border-radius: 99px;
  overflow: hidden;
}

.rating-fill {
  height: 100%;
  width: 84%;
  background: var(--bar-fill);
  border-radius: 99px;
}

.options {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 8px;
}

.option {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  padding: 10px 8px;
  border-radius: 10px;
  border: 1.5px solid transparent;
}

.option-icon {
  font-size: 18px;
  line-height: 1;
}

.option-label {
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.03em;
}

.option-count {
  font-size: 16px;
  font-weight: 700;
}

.option--yes {
  background: var(--yes-bg);
  border-color: var(--yes-border);
}

.option--yes .option-label {
  color: var(--yes-label);
}

.option--yes .option-count {
  color: var(--yes-count);
}

.option--maybe {
  background: var(--maybe-bg);
  border-color: var(--maybe-border);
}

.option--maybe .option-label {
  color: var(--maybe-label);
}

.option--maybe .option-count {
  color: var(--maybe-count);
}

.option--no {
  background: var(--no-bg);
  border-color: var(--no-border);
}

.option--no .option-label {
  color: var(--no-label);
}

.option--no .option-count {
  color: var(--no-count);
}

.card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.avatars {
  display: flex;
  align-items: center;
}

.avatar {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
  color: var(--avatar-text);
  border: 2px solid var(--card-bg);
  margin-left: -6px;
}

.avatars .avatar:first-child {
  margin-left: 0;
}

.av1 { background: var(--av1-bg); }
.av2 { background: var(--av2-bg); }
.av3 { background: var(--av3-bg); }
.av4 { background: var(--av4-bg); color: var(--av4-color); }

.vote-btn {
  background: var(--btn-bg);
  color: var(--btn-color);
  border: none;
  border-radius: 8px;
  padding: 8px 18px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
}
